def delete_directory(
        fs: Annotated[FileSystem, Depends("filesystem")],
        path: str,
        recursive: bool = False,
) -> dict[str, str]:
    """
    Deletes a directory, optionally recursively.

    :param path: The path to the directory to delete (relative or absolute).
    :param recursive: If True, delete directory and all contents (default: False).
    :return: Success message dict.
    """
    abs_path = fs.resolve_path(path)

    if not fs.exists(abs_path):
        raise FileNotFoundError(f"Directory not found at path: {abs_path}")

    if not fs.is_directory(abs_path):
        raise ValueError(f"Path is not a directory: {abs_path}")

    # Check if empty (only if not recursive)
    if not recursive:
        children = fs.list_dir(abs_path)
        if children:
            raise ValueError(f"Directory not empty: {abs_path}. Use recursive=True to delete non-empty directories.")

    # Perform deletion
    if recursive:
        _delete_path_recursive(fs, abs_path)
    else:
        # 修复：删除时用规范化路径
        fs.directories.discard(fs._normalize_dir(abs_path))

    return {
        "message": f"Successfully deleted directory: {abs_path}" +
                   (" (recursively)" if recursive else " (empty)"),
        "deletedPath": abs_path,
        "wasRecursive": recursive,
    }

def move_path(
        fs: Annotated[FileSystem, Depends("filesystem")],
        source_path: str,
        destination_path: str,
) -> dict[str, str]:
    """
    Moves or renames a file or directory.

    :param source_path: Source path (relative or absolute).
    :param destination_path: Destination path (relative or absolute).
    :return: Success message dict.
    """
    src = fs.resolve_path(source_path)
    dst = fs.resolve_path(destination_path)

    if src == dst:
        raise ValueError("Source and destination paths cannot be the same.")

    if not fs.exists(src):
        raise FileNotFoundError(f"Source path not found: {src}")

    parent_dst = fs._get_parent(dst)
    if parent_dst != "/" and not fs.is_directory(parent_dst):
        raise ValueError(f"Destination parent directory does not exist: {parent_dst}")

    if fs.exists(dst):
        raise ValueError(f"Destination path already exists: {dst}")

    # Perform move
    if fs.is_directory(src):
        _move_directory(fs, src, dst)
    else:
        _move_file(fs, src, dst)

    return {
        "message": f"Successfully moved {src} to {dst}",
        "sourcePath": src,
        "destinationPath": dst,
    }

def update_file(
        fs: Annotated[FileSystem, Depends("filesystem")],
        path: str,
        blocks: List[Dict[str, str]],
        useRegex: bool = False,
        replaceAll: bool = False,
) -> dict[str, Any]:
    """
    Performs targeted search-and-replace operations within an existing file.

    :param path: Path to the file to update (must exist).
    :param blocks: List of {'search': str, 'replace': str} blocks.
    :param useRegex: If True, treat 'search' as regex pattern (default: False).
    :param replaceAll: If True, replace all matches; else only first (default: False).
    :return: Dict with message, path, and block stats.
    """
    # 修复：增加输入校验，避免空blocks或空search
    if not blocks:
        raise ValueError("At least one search/replace block is required.")

    for i, block in enumerate(blocks):
        if not isinstance(block, dict):
            raise ValueError(f"Block {i + 1} must be a dictionary (got {type(block).__name__}).")
        if "search" not in block or not block["search"]:
            raise ValueError(f"Search pattern cannot be empty in block {i + 1}.")

    abs_path = fs.resolve_path(path)

    if not fs.is_file(abs_path):
        raise FileNotFoundError(f"File not found at path: {abs_path}. Cannot update a non-existent file.")

    current_content = fs.files[abs_path]
    updated_content = current_content
    blocks_applied = 0
    blocks_failed = 0
    total_replacements = 0

    for i, block in enumerate(blocks):
        search = block.get("search", "")
        replace = block.get("replace", "")

        block_made_change = False
        replacements_in_block = 0

        try:
            if useRegex:
                # Compile regex with proper flags
                flags = re.DOTALL  # Similar to JS default behavior
                try:
                    pattern = re.compile(search, flags)
                except re.error as e:
                    raise ValueError(f"Invalid regular expression pattern in block {i + 1}: \"{search}\". Error: {e}")

                # Find all matches first
                matches = pattern.findall(updated_content)
                if matches:
                    if replaceAll:
                        # Global replace
                        updated_content, count = pattern.subn(replace, updated_content)
                        replacements_in_block = count
                    else:
                        # Replace only first
                        updated_content, count = pattern.subn(replace, updated_content, count=1)
                        replacements_in_block = count
                    block_made_change = True
            else:
                # Exact string matching
                if replaceAll:
                    parts = updated_content.split(search)
                    if len(parts) > 1:
                        updated_content = replace.join(parts)
                        replacements_in_block = len(parts) - 1
                        block_made_change = True
                else:
                    index = updated_content.find(search)
                    if index != -1:
                        updated_content = (
                                updated_content[:index] + replace + updated_content[index + len(search):]
                        )
                        replacements_in_block = 1
                        block_made_change = True

        except Exception as e:
            if useRegex:
                raise ValueError(f"Error processing regex block {i + 1}: {e}")
            else:
                raise RuntimeError(f"Error processing string block {i + 1}: {e}")

        if block_made_change:
            blocks_applied += 1
            total_replacements += replacements_in_block
        else:
            blocks_failed += 1

    # Only update if changes were made
    if total_replacements > 0:
        fs.files[abs_path] = updated_content
        replace_msg = f"Made {total_replacements} replacement(s) across {blocks_applied} block(s)."
        message = f"Successfully updated file {abs_path}. {replace_msg} {blocks_failed} block(s) failed (search criteria not found)."
    else:
        message = f"No changes applied to file {abs_path}. {blocks_failed} block(s) failed (search criteria not found)."

    return {
        "message": message,
        "updatedPath": abs_path,
        "blocksApplied": blocks_applied,
        "blocksFailed": blocks_failed,
    }
